using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private StringFormatter _formatter = null!;

    [TestInitialize]
    public void Setup()
    {
        _formatter = new StringFormatter();
    }

    #region FormatPhoneNumber

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_FormatsCorrectly()
    {
        var result = _formatter.FormatPhoneNumber("1234567890");

        Assert.AreEqual("(123) 456-7890", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith(result, "(555)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith(result, "4567");
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    #endregion

    #region BuildGreeting

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_FormatsCorrectly()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithDearTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_AnyInput_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Doe", "Ms.");

        Assert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ContainsName()
    {
        var result = _formatter.BuildGreeting("Williams", "Prof.");

        Assert.Contains(result, "Williams");
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    #endregion

    #region GenerateSlug

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_RemovesSpecialChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!");

        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithLetter_StartsWithLowercaseLetter()
    {
        var result = _formatter.GenerateSlug("My Article Title");

        Assert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_DoesNotEndWithHyphen()
    {
        var result = _formatter.GenerateSlug("Trailing Punctuation!!!");

        Assert.IsFalse(result.EndsWith('-'));
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartWithHyphen()
    {
        var result = _formatter.GenerateSlug("   Leading Spaces");

        Assert.IsFalse(result.StartsWith('-'));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_ThrowsArgumentException(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    #endregion

    #region FormatCurrency

    [TestMethod]
    public void FormatCurrency_WithDefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_WithEuroSymbol_StartsWithEuro()
    {
        var result = _formatter.FormatCurrency(42.50m, "€");

        Assert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_WithCents_FormatsCorrectly()
    {
        var result = _formatter.FormatCurrency(9.99m, "£");

        Assert.AreEqual("£9.99", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.00m);

        Assert.Contains(result, "-");
    }

    #endregion
}

